import React from 'react';
import './Box.scss';
import Icons from '../Icons';

export default props => (
  <a href={props.link} className={`Box Box-${props.tag} ${props.className}`}>
    <h3 className="Box-title">{props.title}</h3>
    <img className="Box-icon" src={Icons[props.tag]} alt="" />
    <p className="Box-content">{props.children}</p>
  </a>
);
